olicy:"Open Package Policy",openPackageDesc:"Our community is built on trust. Travelers have the right to inspect package contents during pickup to ensure safety code compliance.",insuranceProtection:"Insurance Protection",insuranceDesc:"Every verified shipment is backed by our Insurance Protection Policy through our secure escrow system.",terms:"Terms",privacy:"Privacy",faqsTitle:"FAQs",goToDashboard:"Go to Dashboard",trustedBy:"Trusted by 10k+ Travelers worldwide.",reimagineLogistics:"Re-imagine logistics.",aboutSummary:"We're building the most human-centric logistics network in the world. Bago connects travelers with people who need to send packages globally.",coreValuesSubtitle:"The principles that guide every feature we build.",packagesSent:"Packages Sent",verifiedTravelers:"Verified Travelers",countriesCovered:"Countries Covered",averageRating:"Average Rating",joinMovement:"Join the movement.",joinMovementDesc:"Become part of the most human-centric logistics network in the world. Start sending or start earning today.",howBagoWorksTitle:"How Bago works.",safetyFirst:"Safety First",prohibited_IllegalSubstances:"Illegal Substances",prohibited_FlammableItems:"Flammable Items",prohibited_LiveAnimals:"Live Animals",prohibited_PrescriptionDrugs:"Prescription Drugs",prohibited_PerishableFood:"Perishable Food",prohibited_LiquidLiquids:"Liquid Liquids",prohibited_AerosolSprays:"Aerosol Sprays",prohibited_Weaponry:"Weaponry",readyToGetStarted:"Ready to get started?",joinThousandsDesc:"Join thousands of members already trusting Bago for their logistics and travel needs.",findRoutes:"Find Routes",preparingDashboard:"Preparing your dashboard...",somethingWentWrong:"Something went wrong",troubleLoadingSection:"We had trouble loading this section. Please try refreshing or return to overview.",refreshPage:"Refresh Page",backToOverview:"Back to Overview",personalDashboard:"Personal Dashboard",backToSite:"← Back to site",verified:"Verified",unverified:"Unverified",fullAccessEnab